		"success": true,
		"message": "Webhook configured successfully",
	})
}

// validateWebhookURL performs additional security validations on the webhook URL
func validateWebhookURL(u *url.URL) error {
	host := u.Hostname()

	// Prevent localhost/internal IP addresses
	ip := net.ParseIP(host)
	if ip != nil {
		if ip.IsLoopback() || ip.IsPrivate() || ip.IsUnspecified() {
			return fmt.Errorf("webhook URL cannot point to private/local addresses")
		}
	} else {
		// If host is not an IP address, resolve it and check the IP
		ips, err := net.LookupIP(host)
		if err != nil {
			return fmt.Errorf("could not resolve hostname: %v", err)
		}

		for _, ip := range ips {
			if ip.IsLoopback() || ip.IsPrivate() || ip.IsUnspecified() {
				return fmt.Errorf("webhook URL resolves to private/local addresses")
			}
		}
	}

	// Prevent URLs with unusual characters in host that could indicate obfuscated addresses
	if strings.Contains(host, "%") || strings.Contains(host, "..") {
		return fmt.Errorf("webhook URL contains invalid characters in hostname")
	}

	return nil
}

