// Global variable to store the configured webhook URL
var configuredWebhookURL string

func ConfigureWebhook(ctx *fiber.Ctx) error {
	type RequestBody struct {
		WebhookURL string `json:"webhook_url"`
	}

	var reqBody RequestBody
	if err := ctx.BodyParser(&reqBody); err != nil {
		return ctx.JSON(fiber.Map{
			"error": "Invalid JSON format",
		})
	}

	webhookURL := reqBody.WebhookURL
	if webhookURL == "" {
		return ctx.JSON(fiber.Map{
			"error": "webhook_url is required",
		})
	}

	// Create HTTP client with 3 second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create a context with timeout
	ctxWithTimeout, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	// Create GET request to validate the webhook URL
	req, err := http.NewRequestWithContext(ctxWithTimeout, http.MethodGet, webhookURL, nil)
	if err != nil {
		return ctx.JSON(fiber.Map{
			"error": "Failed to create validation request",
		})
	}

	// Send the test request
	resp, err := client.Do(req)
	if err != nil {
		return ctx.JSON(fiber.Map{
			"error":   "Webhook validation failed",
			"details": err.Error(),
		})
	}
	defer resp.Body.Close()

	// If the request was successful, save the configuration
	configuredWebhookURL = webhookURL

	return ctx.JSON(fiber.Map{
		"success":      true,
		"webhook_url":  webhookURL,
		"status_code":  resp.StatusCode,
		"message":      "Webhook configured successfully",
	})
}

func main() {
	app := fiber.New()

	app.Post("/configure-webhook", ConfigureWebhook)

	app.Listen(":3000")
}

