// ConfigureWebhook handles the webhook configuration
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON request body
	var config WebhookConfig
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.JSON(fiber.Map{
			"error": "Invalid JSON format",
		})
	}

	// Validate that webhook_url is provided
	if config.WebhookURL == "" {
		return ctx.JSON(fiber.Map{
			"error": "webhook_url is required",
		})
	}

	// Create an HTTP client with a 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send a GET request to test the webhook URL
	resp, err := client.Get(config.WebhookURL)
	if err != nil {
		log.Errorf("Error testing webhook URL: %v", err)
		return ctx.JSON(fiber.Map{
			"error":   "Failed to connect to webhook URL",
			"details": err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if the response status indicates success
	success := resp.StatusCode >= 200 && resp.StatusCode < 300

	// In a real application, you might want to save this to a database
	// For now, we'll just return the result
	return ctx.JSON(fiber.Map{
		"success":      success,
		"webhook_url":  config.WebhookURL,
		"status_code":  resp.StatusCode,
		"message":      "Webhook configured successfully",
	})
}

func main() {
	app := fiber.New()

	app.Post("/configure-webhook", ConfigureWebhook)

	log.Fatal(app.Listen(":3000"))
}

