// isPrivateIP checks if the hostname resolves to a private IP address
func isPrivateIP(hostname string) bool {
	// If hostname contains only numbers and dots, try to parse as IP directly
	ip := net.ParseIP(hostname)
	if ip != nil {
		return isPrivateNetwork(ip)
	}

	// Otherwise resolve the hostname to IP addresses
	ips, err := net.LookupIP(hostname)
	if err != nil {
		// If DNS lookup fails, return true to be safe
		return true
	}

	for _, ip := range ips {
		if isPrivateNetwork(ip) {
			return true
		}
	}
	return false
}

// isPrivateNetwork checks if an IP address belongs to private network ranges
func isPrivateNetwork(ip net.IP) bool {
	privateCIDRs := []string{
		"10.0.0.0/8",      // Class A private network
		"172.16.0.0/12",   // Class B private network
		"192.168.0.0/16",  // Class C private network
		"127.0.0.0/8",     // Loopback
		"169.254.0.0/16",  // Link-local
		"::1/128",         // IPv6 loopback
		"fc00::/7",        // IPv6 unique local addr
		"fe80::/10",       // IPv6 link-local addr
	}

	for _, cidr := range privateCIDRs {
		_, network, _ := net.ParseCIDR(cidr)
		if network.Contains(ip) {
			return true
		}
	}
	return false
}

