package main

import (
	"context"
	"time"

	"github.com/gofiber/fiber/v2"
	"github.com/gofiber/fiber/v2/log"
)

type WebhookConfig struct {
	URL string `json:"webhook_url"`
}

type Response struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

func ConfigureWebhook(ctx *fiber.Ctx) error {
	var config WebhookConfig

	if err := ctx.BodyParser(&config); err != nil {
		return ctx.JSON(Response{
			Success: false,
			Message: "Invalid request body",
		})
	}

	if config.URL == "" {
		return ctx.JSON(Response{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create a GET request to test the webhook URL
	req, err := http.NewRequestWithContext(context.Background(), "GET", config.URL, nil)
	if err != nil {
		return ctx.JSON(Response{
			Success: false,
			Message: "Failed to create test request: " + err.Error(),
		})
	}

	// Send the test request
	resp, err := client.Do(req)
	if err != nil {
		return ctx.JSON(Response{
			Success: false,
			Message: "Failed to validate webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// If the request was successful, consider the URL valid
	if resp.StatusCode >= 200 && resp.StatusCode < 300 {
		// Here you would typically save the configuration to a database or config file
		log.Infof("Webhook configured successfully: %s", config.URL)

		return ctx.JSON(Response{
			Success: true,
			Message: "Webhook configured successfully",
		})
	} else {
		return ctx.JSON(Response{
			Success: false,
			Message: "Webhook validation failed with status: " + resp.Status,
		})
	}
}

func main() {
	app := fiber.New()

	app.Post("/configure-webhook", ConfigureWebhook)

	log.Fatal(app.Listen(":3000"))
}

