// isPrivateAddress checks if the hostname resolves to a private IP address
func isPrivateAddress(hostname string) bool {
	ips, err := net.LookupIP(hostname)
	if err != nil {
		// If we can't resolve the hostname, assume it's not private
		// In a production system, you might want to handle this differently
		return false
	}

	for _, ip := range ips {
		if ip.IsLoopback() || ip.IsPrivate() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
			return true
		}
	}

	// Also check for localhost as a special case
	return strings.ToLower(hostname) == "localhost"
}

