type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

type Response struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

var savedWebhookURL string

func ConfigureWebhook(ctx *fiber.Ctx) error {
	var config WebhookConfig

	// Parse the JSON body
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.JSON(Response{
			Success: false,
			Message: "Invalid JSON format",
		})
	}

	// Validate that webhook_url is provided
	if config.WebhookURL == "" {
		return ctx.JSON(Response{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Test the webhook URL with a GET request
	req, err := http.NewRequestWithContext(context.Background(), http.MethodGet, config.WebhookURL, nil)
	if err != nil {
		return ctx.JSON(Response{
			Success: false,
			Message: "Failed to create test request: " + err.Error(),
		})
	}

	resp, err := client.Do(req)
