package main

import (
	"time"

	"github.com/gofiber/fiber/v2"
)

type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

type Response struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

func ConfigureWebhook(ctx *fiber.Ctx) error {
	var config WebhookConfig
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.JSON(Response{
			Success: false,
			Message: "Failed to parse JSON",
		})
	}

	if config.WebhookURL == "" {
		return ctx.JSON(Response{
			Success: false,
			Message: "Webhook URL is required",
		})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send a GET request to test the webhook URL
	resp, err := client.Get(config.WebhookURL)
	if err != nil {
		return ctx.JSON(Response{
			Success: false,
			Message: "Failed to validate webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if the request was successful
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.JSON(Response{
			Success: false,
			Message: "Webhook URL validation failed with status: " + resp.Status,
		})
	}

	// Here you would typically save the webhook URL to a database or config file
	// For this example, we'll just return a success message

	return ctx.JSON(Response{
		Success: true,
		Message: "Webhook configured successfully",
	})
}

func main() {
	app := fiber.New()
	app.Post("/configure-webhook", ConfigureWebhook)
	app.Listen(":3000")
}

