		blockedPorts := []string{"22", "23", "3389", "5900", "6379", "5432", "3306", "11211"}
		for _, blockedPort := range blockedPorts {
			if port == blockedPort {
				return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
					"success": false,
