	defer cancel()

	httpReq, err := http.NewRequestWithContext(reqContext, "GET", req.WebhookURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to create test request",
		})
	}

	httpReq.Header.Set("User-Agent", "Webhook-Configuration-Service/1.0")

	resp, err := client.Do(httpReq)
	if err != nil {
