// Global variable to store the configured webhook URL
var configuredWebhookURL string

func ConfigureWebhook(ctx *fiber.Ctx) error {
	var config WebhookConfig

	// Parse the JSON body
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.JSON(Response{
			Success: false,
			Message: "Invalid JSON format",
		})
	}

	// Validate that webhook_url is provided
	if config.URL == "" {
