			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Create HTTP client with 3 second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create a GET request to test the webhook URL
	req, err := http.NewRequestWithContext(context.Background(), "GET", config.URL, nil)
	if err != nil {
		return ctx.JSON(Response{
			Success: false,
			Message: "Failed to create test request: " + err.Error(),
		})
	}

	// Send the test request
	resp, err := client.Do(req)
	if err != nil {
