func ConfigureWebhook(ctx *fiber.Ctx) error {
	var config WebhookConfig
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.JSON(Response{
			Success: false,
			Message: "Invalid JSON format",
		})
	}

	if config.WebhookURL == "" {
		return ctx.JSON(Response{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Validate the webhook URL by sending a test GET request
	client := &http.Client{
		Timeout: 3 * time.Second, // Set timeout to 3 seconds
	}

	req, err := http.NewRequest("GET", config.WebhookURL, nil)
	if err != nil {
		return ctx.JSON(Response{
			Success: false,
			Message: "Failed to create test request: " + err.Error(),
		})
	}

	resp, err := client.Do(req)
	if err != nil {
		return ctx.JSON(Response{
			Success: false,
			Message: "Failed to validate webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if the response status is successful (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.JSON(Response{
			Success: false,
			Message: "Webhook URL validation failed with status: " + resp.Status,
		})
	}

	// Save the validated webhook URL (in a real app, this might go to a database)
	currentWebhookURL = config.WebhookURL

	return ctx.JSON(Response{
		Success: true,
		Message: "Webhook configured successfully",
	})
}

func main() {
	app := fiber.New()

	app.Post("/configure-webhook", ConfigureWebhook)

