	resp, err := client.Do(request)
	if err != nil {
		return ctx.JSON(WebhookResponse{
			Success: false,
			Message: "Failed to connect to webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if the request was successful (status code 2xx)
	success := resp.StatusCode >= 200 && resp.StatusCode < 300

	// Here you would typically save the webhook configuration to your storage
